function BalanceBelowZero(operations: seq<int>): bool
{
    exists i: nat :: i < |operations| && SumPrefix(operations, i) < 0
}

function SumPrefix(operations: seq<int>, upTo: nat): int
    requires upTo <= |operations|
{
    if upTo == 0 then 0
    else SumPrefix(operations, upTo - 1) + operations[upTo - 1]
}

method below_zero(operations: seq<int>) returns (result: bool)
    ensures result == BalanceBelowZero(operations)

function IsPalindrome(s: string): bool
{
    forall i :: 0 <= i < |s| / 2 ==> s[i] == s[|s| - 1 - i]
}

function LongestPalindromicSuffix(string_: string): string
{
    if |string_| == 0 then ""
    else
        var suffix := string_[|string_| - 1..];
        if IsPalindrome(suffix) then suffix
        else LongestPalindromicSuffix(string_[..|string_| - 1])
}

function Reverse(s: string): string
{
    if |s| == 0 then ""
    else Reverse(s[1..]) + [s[0]]
}

function Reference(string_: string): string
{
    if |string_| == 0 then ""
    else
        var suffix := LongestPalindromicSuffix(string_);
        var prefix := string_[..|string_| - |suffix|];
        string_ + Reverse(prefix)
}

method make_palindrome(string_: string) returns (result: string)
    ensures result == Reference(string_)

function string_sequence_helper(n: int): string
    requires n >= 0
{
    if n == 0 then "0"
    else 
        var prev := string_sequence_helper(n - 1);
        prev + " " + int_to_string(n)
}

function int_to_string(x: int): string
    requires x >= 0
{
    if x < 10 then 
        var digit := x as char;
        [digit]
    else
        var d := x / 10;
        var r := x % 10;
        int_to_string(d) + [r as char]
}

method string_sequence(n: int) returns (result: string)
    requires n >= 0
    ensures result == string_sequence_helper(n)
